export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  const hooks = resolveTurnHooks(options.hooks);
  const playerActionResult = applyPlayerAction(state, action);
  if (isActionResolverIllegal(playerActionResult)) {
    return illegalStep(state, action, playerActionResult.reason);
  }

  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
    ...playerActionResult.events,
  ];

  let nextState = playerActionResult.state;

  if (!isTerminal(nextState)) {

  previousActionKey: null,
  previousProgressKey: null,
  repeatCount: 0
};
let reachedStairs = false;
let questCompleted = floorQuestCompleted(state, candidate.manifest.quest);
let turns = 0;

while (
  state.run.terminalStatus === "ACTIVE" &&
  turns < maxTurns &&
  !reachedStairs &&
  !questCompleted
) {
  const view = createBotStateView(state, {
    policyName: policy.name,
    memory
  });
  memory = updateBotMemory(memory, view);
  const decided = legalizeDecision(view, policy.decide(view));
  const breaker = breakStall(view, decided, stall);
  const action = breaker.action;
  stall = breaker.stall;
  turns += 1;

  if (action.kind === "descend" && hasAction(view, action)) {
    reachedStairs = true;
    break;
  }

  const stepped = stepRun(state, action, UNUSED_PROVIDER);
  if (!stepped.ok) {
    throw new Error(
      `Gate 2 bot step failed at turn ${state.run.turn} for ${policy.name}: ${stepped.error.message}`
    );
  }

  state = stepped.state;
  questCompleted = floorQuestCompleted(state, candidate.manifest.quest);
}

return {
  policy: policy.name,
  seed,
  reachedStairs,
  questCompleted,
  cleared: reachedStairs || questCompleted,
  hpRetention:
    state.player.hp.max <= 0
      ? 0
      : state.player.hp.current / state.player.hp.max,
  turns,
  died:
    state.run.terminalStatus ===
    defaultConfig.runStructure.terminalStates.loss,
  terminal: state.run.terminalStatus,
  maxTurnsHit:
    turns >= maxTurns &&
    state.run.terminalStatus === "ACTIVE" &&
    !reachedStairs &&
    !questCompleted

  if (!isTerminal(nextState)) {
    for (const actor of actorsInTurnOrder(nextState)) {
      events.push(
        turnEvent(nextState.run.turn, "actor_turn", {
          actorId: actor.id,
        }),
      );

      const result = normalizeHookResult(
        hooks.actorTurn({
          state: nextState,
          actor,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    for (const hook of TICK_HOOK_ORDER) {
      events.push(
        turnEvent(nextState.run.turn, "tick_hook", {
          hook,
        }),
      );

      const result = normalizeHookResult(
        hooks.ticks[hook]({
          state: nextState,
          hook,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    nextState = advanceTurn(nextState);

    const terminal = forcedTerminalFor(nextState);
    if (terminal !== null) {
      nextState = withTerminalStatus(nextState, terminal.status);
      events.push(
        turnEvent(nextState.run.turn, "terminal_state", {
          status: terminal.status,
          reason: terminal.reason,
        }),
      );
    }
  }

  nextState = appendLog(nextState, events);

  return {
    state: nextState,
    events,
  };
};

